281	let state = {};
282	const STORAGE_KEY = "weg_supplier_tracker_v1";
283	function loadState(){
284	  try{
285	    const raw = localStorage.getItem(STORAGE_KEY);
286	    if(raw) state = JSON.parse(raw);
287	  }catch(e){ state = {}; }
288	}
289	let _saveTimer=null;
290	function saveState(){
291	  try{
292	    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
293	    const f = document.getElementById("flash");
294	    if(f){ f.classList.add("show"); clearTimeout(_saveTimer); _saveTimer=setTimeout(()=>f.classList.remove("show"),900); }
295	  }catch(e){
296	    const f = document.getElementById("flash");
297	    if(f){ f.textContent="⚠ could not save (storage blocked)"; f.style.color="var(--amber)"; f.classList.add("show"); }
298	  }
299	}
300	function sState(id){ if(!state[id]) state[id]={}; return state[id]; }
301	
302	// Returns the live to-do list for a supplier as [{id, t, d}].
303	// Seeds once from the supplier defaults, then lives entirely in state
304	// so items can be added and deleted.
305	function getTodos(s){
306	  const st = sState(s.id);
307	  if(!st.todoList){
308	    st.todoList = (s.todos||[]).map((t,i)=>({ id:"d"+i, t:t.t, d:t.d }));
309	  }
310	  return st.todoList;
311	}
