320	    const st = sState(s.id);
321	    const curStatus = st.status || s.status;
322	    c[curStatus]++;
323	    if(filter!=="all" && filter!==curStatus) return;
324	
325	    const card=document.createElement("div");
326	    card.className="card"+(st.open?" open":"");
327	    const sm=STATUS_META[curStatus];
328	
329	    const todos = getTodos(s);
330	    const todoDone = todos.filter(t=>t.d).length;
331	    const todoTotal = todos.length;
